{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/layer_2_gov/schemas/carrier-transition.schema.json",
  "title": "DSET carrier-transition ledger",
  "type": "object",
  "additionalProperties": false,
  "required": ["schema_version", "transitions"],
  "properties": {
    "schema_version": {"const": "1.0"},
    "transitions": {
      "type": "array",
      "items": {"$ref": "#/$defs/transition"}
    }
  },
  "$defs": {
    "sha256": {"type": "string", "pattern": "^[0-9a-f]{64}$"},
    "gitObject": {"type": "string", "pattern": "^[0-9a-f]{40,64}$"},
    "transition": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "id",
        "kind",
        "authority_decision",
        "carrier_ids",
        "semantic_ids",
        "original_path",
        "original_format",
        "original_sha256",
        "source_git_blob",
        "current_path",
        "current_format",
        "current_sha256",
        "source_semantic_sha256",
        "current_semantic_sha256",
        "null_paths",
        "declared_loss",
        "source_commit",
        "transitioned_at",
        "llm_session_ids"
      ],
      "properties": {
        "id": {
          "type": "string",
          "pattern": "^DSET-CARRIER-TRANSITION-[A-F0-9]{16}$"
        },
        "kind": {
          "enum": ["structured_yaml", "markdown_frontmatter", "markdown_links", "carrier_relocation"]
        },
        "authority_decision": {
          "enum": [
            "DSET-DECISION-GOV-018",
            "DSET-REQUIREMENT-GOV-041",
            "DSET-REQUIREMENT-GOV-044"
          ]
        },
        "carrier_ids": {
          "type": "array",
          "uniqueItems": true,
          "items": {
            "type": "string",
            "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$"
          }
        },
        "semantic_ids": {
          "type": "array",
          "uniqueItems": true,
          "items": {
            "type": "string",
            "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$"
          }
        },
        "original_path": {"type": "string", "minLength": 1},
        "original_format": {"type": "string", "minLength": 1},
        "original_sha256": {"$ref": "#/$defs/sha256"},
        "source_git_blob": {"$ref": "#/$defs/gitObject"},
        "current_path": {"type": "string", "minLength": 1},
        "current_format": {"type": "string", "minLength": 1},
        "current_sha256": {"$ref": "#/$defs/sha256"},
        "source_semantic_sha256": {"$ref": "#/$defs/sha256"},
        "current_semantic_sha256": {"$ref": "#/$defs/sha256"},
        "null_paths": {
          "type": "array",
          "uniqueItems": true,
          "items": {"type": "string", "pattern": "^/"}
        },
        "declared_loss": {"type": "array", "maxItems": 0},
        "link_rewrites": {
          "type": "array",
          "minItems": 1,
          "items": {
            "type": "object",
            "additionalProperties": false,
            "required": ["source", "target", "original_path", "current_path"],
            "properties": {
              "source": {"type": "string", "minLength": 1},
              "target": {"type": "string", "minLength": 1},
              "original_path": {"type": "string", "minLength": 1},
              "current_path": {"type": "string", "minLength": 1}
            }
          }
        },
        "source_commit": {"$ref": "#/$defs/gitObject"},
        "transitioned_at": {"type": "string", "format": "date-time"},
        "llm_session_ids": {
          "type": "array",
          "minItems": 1,
          "uniqueItems": true,
          "items": {
            "type": "string",
            "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$"
          }
        }
      },
      "allOf": [
        {
          "if": {"properties": {"kind": {"const": "markdown_links"}}},
          "then": {"required": ["link_rewrites"]}
        }
      ]
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/layer_2_gov/schemas/change.schema.json",
  "title": "DSET change manifest",
  "type": "object",
  "required": ["schema_version", "id", "profile", "status", "packages", "pull_request", "requirements", "tests", "evals"],
  "properties": {
    "schema_version": {"oneOf": [{"enum": [1.0, 1.1]}, {"type": "string", "pattern": "^1\\.(?:0|1)-draft$"}, {"const": "1.2"}]},
    "id": {"type": "string", "minLength": 1},
    "slug": {"$ref": "#/$defs/kebab"},
    "profile": {"enum": ["small", "standard", "large", "defect", "adoption"]},
    "status": {"enum": ["proposed", "in-progress", "failed", "verified", "archive-ready", "archived"]},
    "primary_layer": {"$ref": "#/$defs/layer"},
    "affected_layers": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/layer"}},
    "workspace": {"$ref": "#/$defs/workspace"},
    "dependencies": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/dependency"}},
    "priority": {"$ref": "#/$defs/priority"},
    "llm_session_ids": {"$ref": "#/$defs/llm_session_ids"},
    "rationale": {"$ref": "#/$defs/rationale"},
    "target": {"$ref": "#/$defs/target"},
    "packages": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"type": "string"}},
    "pull_request": {"$ref": "#/$defs/pr"},
    "release": {"oneOf": [{"$ref": "#/$defs/release"}, {"$ref": "#/$defs/layered_release"}]},
    "intake": {"$ref": "#/$defs/intake_ids"},
    "related_pull_requests": {"type": "array", "items": {"$ref": "#/$defs/related_pr"}},
    "requirements": {"$ref": "#/$defs/legacy_ids"},
    "tests": {"$ref": "#/$defs/legacy_ids"},
    "evals": {"$ref": "#/$defs/legacy_ids"},
    "adrs": {"$ref": "#/$defs/legacy_ids"},
    "decisions": {"$ref": "#/$defs/decision_ids"},
    "contracts": {"$ref": "#/$defs/contract_ids"},
    "stories": {"$ref": "#/$defs/story_ids"},
    "outcomes": {"$ref": "#/$defs/outcome_ids"},
    "archive": {"oneOf": [{"$ref": "#/$defs/legacy_archive"}, {"$ref": "#/$defs/layered_archive"}]}
  },
  "$defs": {
    "layer": {"enum": ["meta", "gov", "tool", "skill", "ops"]},
    "kebab": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"},
    "sha_or_pending": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"const": "pending"}]},
    "change_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-CHANGE-(?:META|GOV|TOOL|SKILL|OPS)-[0-9]{3,}$"},
    "trace_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-(?:DECISION|REQUIREMENT|CONSTRAINT|CONTRACT|STORY|OUTCOME|SCENARIO|INVARIANT|QUESTION|CONFLICT|RISK|OPPORTUNITY|PROBLEM|DEFECT|GAP|DEBT|TEST|EVAL|EVALUATION|TASK|CHANGE)(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"},
    "llm_session_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$"}},
    "rationale": {"type": "string", "minLength": 1, "maxLength": 4096},
    "priority": {"type": "string", "minLength": 1},
    "legacy_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z0-9]+(?:-[A-Z0-9]+)+$"}},
    "requirement_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-REQUIREMENT(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "test_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-TEST(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "eval_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-(?:EVAL|EVALUATION)(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "intake_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-(?:QUESTION|CONFLICT|RISK|OPPORTUNITY|PROBLEM|DEFECT|GAP|DEBT)(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "decision_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-DECISION(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "contract_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-CONTRACT(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "story_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-STORY(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "outcome_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-OUTCOME(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
    "pr": {
      "type": "object",
      "required": ["repository", "number", "url"],
      "properties": {
        "repository": {"type": "string", "pattern": "^[^/]+/[^/]+$"},
        "number": {"oneOf": [{"type": "integer", "minimum": 1}, {"const": "pending"}]},
        "url": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "exact_pr": {
      "type": "object",
      "required": ["repository", "number", "url"],
      "properties": {
        "repository": {"type": "string", "pattern": "^[^/]+/[^/]+$"},
        "number": {"type": "integer", "minimum": 1},
        "url": {"type": "string", "format": "uri", "pattern": "^https://"}
      },
      "additionalProperties": false
    },
    "workspace": {
      "type": "object",
      "required": ["isolation", "branch", "base_ref", "base_commit", "head_commit"],
      "properties": {
        "isolation": {"enum": ["integration-branch", "branch-worktree"]},
        "branch": {"type": "string", "minLength": 1},
        "base_ref": {"type": "string", "minLength": 1},
        "base_commit": {"$ref": "#/$defs/sha_or_pending"},
        "head_commit": {"$ref": "#/$defs/sha_or_pending"}
      },
      "additionalProperties": false
    },
    "dependency": {
      "type": "object",
      "required": ["change_id", "pull_request", "required_commit", "consumes", "claim", "use", "evidence", "checked_at", "reopen_when", "status"],
      "properties": {
        "change_id": {"$ref": "#/$defs/change_id"},
        "pull_request": {"$ref": "#/$defs/pr"},
        "required_commit": {"$ref": "#/$defs/sha_or_pending"},
        "consumes": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/trace_id"}},
        "claim": {"type": "string", "minLength": 1},
        "use": {"type": "string", "minLength": 1},
        "evidence": {"type": "string", "minLength": 1},
        "checked_at": {"type": "string", "format": "date"},
        "reopen_when": {"type": "string", "minLength": 1},
        "status": {"enum": ["planned", "available", "integrated", "blocked", "stale"]}
      },
      "allOf": [
        {
          "if": {"properties": {"status": {"enum": ["available", "integrated"]}}, "required": ["status"]},
          "then": {
            "properties": {
              "pull_request": {"$ref": "#/$defs/exact_pr"},
              "required_commit": {"type": "string", "pattern": "^[0-9a-f]{40}$"}
            }
          }
        }
      ],
      "additionalProperties": false
    },
    "target": {
      "type": "object",
      "required": ["repository", "work_areas"],
      "properties": {
        "repository": {"type": "boolean"},
        "work_areas": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/kebab"}}
      },
      "oneOf": [
        {
          "properties": {
            "repository": {"const": true},
            "work_areas": {"maxItems": 0}
          }
        },
        {
          "properties": {
            "repository": {"const": false},
            "work_areas": {"minItems": 1}
          }
        }
      ],
      "additionalProperties": false
    },
    "related_pr": {
      "type": "object",
      "required": ["number", "role"],
      "properties": {
        "number": {"type": "integer", "minimum": 1},
        "role": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "release": {
      "oneOf": [
        {"$ref": "#/$defs/release_declaration"},
        {"$ref": "#/$defs/release_reference"}
      ]
    },
    "release_declaration": {
      "type": "object",
      "required": ["policy", "class", "base", "target", "readiness", "candidate_commit"],
      "properties": {
        "policy": {"const": "dset/governance/release.md"},
        "class": {"enum": ["pending", "bootstrap", "small", "normal", "rc", "final", "breaking"]},
        "base": {
          "type": "object",
          "required": ["ref", "commit", "version"],
          "properties": {
            "ref": {"type": "string", "minLength": 1},
            "commit": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"const": "pending"}]},
            "version": {"oneOf": [{"const": "unversioned"}, {"const": "pending"}, {"$ref": "#/$defs/semver"}]}
          },
          "additionalProperties": false
        },
        "target": {"oneOf": [{"const": "pending"}, {"$ref": "#/$defs/semver"}]},
        "readiness": {
          "oneOf": [
            {"const": "pending"},
            {"type": "string", "pattern": "^[A-Za-z0-9][A-Za-z0-9._-]*\\.md$"}
          ]
        },
        "candidate_commit": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"const": "pending"}]}
      },
      "additionalProperties": false
    },
    "release_reference": {
      "type": "object",
      "required": ["owner_change"],
      "properties": {
        "owner_change": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"}
      },
      "additionalProperties": false
    },
    "layered_release": {
      "oneOf": [
        {"$ref": "#/$defs/layered_release_declaration"},
        {"$ref": "#/$defs/layered_release_reference"}
      ]
    },
    "layered_release_declaration": {
      "type": "object",
      "required": ["policy", "class", "base", "target", "readiness", "candidate_commit"],
      "properties": {
        "policy": {"enum": ["dset/scopes/ops/governance/release.md", ".dset/layer_5_ops/procedure-release.md"]},
        "class": {"enum": ["pending", "bootstrap", "small", "normal", "rc", "final", "breaking"]},
        "base": {"$ref": "#/$defs/release_base"},
        "target": {"oneOf": [{"const": "pending"}, {"$ref": "#/$defs/semver"}]},
        "readiness": {
          "oneOf": [
            {"const": "pending"},
            {"type": "string", "pattern": "^[A-Za-z0-9][A-Za-z0-9._-]*\\.md$"}
          ]
        },
        "candidate_commit": {"$ref": "#/$defs/sha_or_pending"}
      },
      "additionalProperties": false
    },
    "layered_release_reference": {
      "type": "object",
      "required": ["owner_change"],
      "properties": {"owner_change": {"$ref": "#/$defs/change_id"}},
      "additionalProperties": false
    },
    "release_base": {
      "type": "object",
      "required": ["ref", "commit", "version"],
      "properties": {
        "ref": {"type": "string", "minLength": 1},
        "commit": {"$ref": "#/$defs/sha_or_pending"},
        "version": {"oneOf": [{"const": "unversioned"}, {"const": "pending"}, {"$ref": "#/$defs/semver"}]}
      },
      "additionalProperties": false
    },
    "semver": {
      "type": "string",
      "pattern": "^(0|[1-9][0-9]*)\\.(0|[1-9][0-9]*)\\.(0|[1-9][0-9]*)(?:-rc\\.[1-9][0-9]*)?$"
    },
    "legacy_archive": {
      "type": "object",
      "required": ["date", "path"],
      "properties": {
        "date": {"type": "string", "format": "date"},
        "path": {"type": "string", "pattern": "^dset/changes/archive/[0-9]{4}-[0-9]{2}-[0-9]{2}-"}
      },
      "additionalProperties": false
    },
    "layered_archive": {
      "type": "object",
      "required": ["date", "path"],
      "properties": {
        "date": {"type": "string", "format": "date"},
        "path": {"type": "string", "pattern": "^dset/(?:meta|gov|tool|skill|ops)/changes/archive/[0-9]{4}-[0-9]{2}-[0-9]{2}-"}
      },
      "additionalProperties": false
    }
  },
  "allOf": [
    {
      "if": {"properties": {"schema_version": {"enum": [1.0, "1.0-draft"]}}},
      "then": {
        "required": ["adrs"],
        "not": {"required": ["decisions"]}
      },
      "else": {
        "required": ["release", "intake", "decisions", "contracts", "llm_session_ids"],
        "not": {"required": ["adrs"]},
        "properties": {
          "requirements": {"$ref": "#/$defs/requirement_ids"},
          "tests": {"$ref": "#/$defs/test_ids"},
          "evals": {"$ref": "#/$defs/eval_ids"},
          "intake": {"$ref": "#/$defs/intake_ids"},
          "decisions": {"$ref": "#/$defs/decision_ids"},
          "contracts": {"$ref": "#/$defs/contract_ids"},
          "stories": {"$ref": "#/$defs/story_ids"},
          "outcomes": {"$ref": "#/$defs/outcome_ids"}
        }
      }
    },
    {
      "if": {"properties": {"schema_version": {"const": "1.2"}}, "required": ["schema_version"]},
