{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/layer_2_gov/schemas/evidence-record.schema.json",
  "title": "DSET native Evidence Record TOML frontmatter",
  "type": "object",
  "required": [
    "schema_version",
    "artifact_type",
    "artifact_subtype",
    "artifact_id",
    "priority",
    "llm_session_ids",
    "subject",
    "producer",
    "method",
    "context",
    "evidence_location",
    "polarity",
    "currentness",
    "reopen_when",
    "relations"
  ],
  "properties": {
    "schema_version": {"const": "1.0"},
    "artifact_type": {"const": "evidence_record"},
    "artifact_subtype": {
      "enum": ["test_result", "evaluation_result", "review_report", "run_record"]
    },
    "artifact_id": {"$ref": "#/$defs/id"},
    "priority": {"type": "string", "minLength": 1},
    "llm_session_ids": {
      "type": "array",
      "uniqueItems": true,
      "items": {
        "type": "string",
        "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$"
      }
    },
    "subject": {"$ref": "#/$defs/subject"},
    "producer": {"$ref": "#/$defs/producer"},
    "method": {"$ref": "#/$defs/method"},
    "context": {
      "type": "array",
      "minItems": 1,
      "items": {"type": "string", "minLength": 1}
    },
    "observed_at": {"type": "string", "format": "date-time"},
    "validity_window": {"$ref": "#/$defs/validity_window"},
    "evidence_location": {"type": "string", "minLength": 1},
    "polarity": {
      "enum": ["supports", "contradicts", "mixed", "inconclusive"]
    },
    "currentness": {"enum": ["current", "stale", "superseded"]},
    "reopen_when": {"type": "string", "minLength": 1},
    "relations": {
      "type": "array",
      "minItems": 1,
      "contains": {
        "type": "object",
        "required": ["type", "target"],
        "properties": {
          "type": {"const": "evidence_for"},
          "target": {"$ref": "#/$defs/id"}
        }
      },
      "items": {"$ref": "#/$defs/relation"}
    },
    "independent_producer": {"type": "boolean"},
    "rival_explanations": {
      "type": "array",
      "minItems": 1,
      "items": {"type": "string", "minLength": 1}
    },
    "limitations": {
      "type": "array",
      "minItems": 1,
      "items": {"type": "string", "minLength": 1}
    },
    "rationale": {"type": "string", "minLength": 1}
  },
  "oneOf": [
    {"required": ["observed_at"], "not": {"required": ["validity_window"]}},
    {"required": ["validity_window"], "not": {"required": ["observed_at"]}}
  ],
  "$defs": {
    "id": {
      "type": "string",
      "pattern": "^[A-Z0-9]+(?:-[A-Z0-9]+)+$"
    },
    "subject": {
      "type": "object",
      "required": ["id", "revision", "intended_use"],
      "properties": {
        "id": {"$ref": "#/$defs/id"},
        "revision": {"type": "string", "minLength": 1, "not": {"const": "pending"}},
        "intended_use": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "producer": {
      "type": "object",
      "required": ["identity", "performed_work"],
      "properties": {
        "identity": {"type": "string", "minLength": 1},
        "performed_work": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "method": {
      "type": "object",
      "required": ["description", "setup"],
      "properties": {
        "description": {"type": "string", "minLength": 1},
        "setup": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "validity_window": {
      "type": "object",
      "required": ["from", "through"],
      "properties": {
        "from": {"type": "string", "format": "date-time"},
        "through": {"type": "string", "format": "date-time"}
      },
      "additionalProperties": false
    },
    "relation": {
      "type": "object",
      "required": ["type", "target"],
      "properties": {
        "type": {
          "enum": [
            "child_of",
            "analysis_of",
            "projection_of",
            "implementation_of",
            "check_of",
            "evidence_for",
            "resolution_of",
            "override_of",
            "replacement_of",
            "relates_to"
          ]
        },
        "target": {"$ref": "#/$defs/id"}
      },
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}

