  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/layer_2_gov/schemas/lifecycle.schema.json",
  "title": "DSET append-only semantic atom lifecycle",
  "type": "object",
  "required": ["schema_version", "events"],
  "properties": {
    "schema_version": {"const": "1.0"},
    "events": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["id", "atom_id", "event", "occurred_at", "llm_session_ids", "related"],
        "properties": {
          "id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-LIFECYCLE-EVENT-[0-9]{3,}$"},
          "atom_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$"},
          "event": {"enum": ["accepted", "answered", "absorbed", "confirmed", "priority_changed", "reopened", "rejected", "resolved", "retired", "withdrawn"]},
          "occurred_at": {"type": "string", "format": "date-time"},
          "priority": {"type": "string", "minLength": 1},
          "related": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+)+$"}},
          "llm_session_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$"}},
          "rationale": {"type": "string", "minLength": 1, "maxLength": 4096}
        },
        "additionalProperties": false
      }
    }
  },
  "additionalProperties": false
}

