        "type": "object",
        "required": ["id", "repository", "revision", "license", "license_file", "use"],
        "properties": {
          "id": {"type": "string"},
          "repository": {"type": "string", "format": "uri"},
          "revision": {"type": "string", "pattern": "^[0-9a-f]{40}$"},
          "license": {"type": "string"},
          "license_file": {"type": "string"},
          "use": {"type": "string"},
          "mappings": {
