        "disposition": {"enum": ["adopted", "adapted", "rejected"]},
        "adaptation_scope": {"type": "string", "minLength": 1},
        "exclusions": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"type": "string", "minLength": 1}}
