{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/layer_3_tool/schemas/dependency-policy.schema.json",
  "title": "DSET exact dependency policy",
  "type": "object",
  "required": ["schema_version", "policy_id", "version", "authority", "exception_authority", "ecosystems", "allow", "deny", "exceptions"],
  "properties": {
