    "policy_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-DEPENDENCY-POLICY-[0-9]{3,}$"},
    "version": {"type": "string", "minLength": 1},
    "authority": {"type": "string", "minLength": 1},
    "exception_authority": {"type": "string", "minLength": 1},
    "ecosystems": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/ecosystem"}},
    "allow": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/dependency"}},
    "deny": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/denial"}},
    "exceptions": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/exception"}}
  },
  "$defs": {
    "ecosystem": {"type": "object", "required": ["id", "manifest", "lockfile", "registry"], "properties": {"id": {"type": "string", "minLength": 1}, "manifest": {"type": "string", "minLength": 1}, "lockfile": {"type": "string", "minLength": 1}, "registry": {"type": "string", "format": "uri"}}, "additionalProperties": false},
    "dependency": {"type": "object", "required": ["ecosystem", "name", "version", "registry", "license", "provenance", "rationale"], "properties": {"ecosystem": {"type": "string", "minLength": 1}, "name": {"type": "string", "minLength": 1}, "version": {"type": "string", "minLength": 1}, "registry": {"type": "string", "format": "uri"}, "license": {"type": "string", "minLength": 1}, "provenance": {"type": "string", "format": "uri"}, "rationale": {"type": "string", "minLength": 1}}, "additionalProperties": false},
    "denial": {"type": "object", "required": ["ecosystem", "name", "rationale"], "properties": {"ecosystem": {"type": "string", "minLength": 1}, "name": {"type": "string", "minLength": 1}, "version": {"type": "string", "minLength": 1}, "rationale": {"type": "string", "minLength": 1}}, "additionalProperties": false},
    "exception": {"type": "object", "required": ["id", "ecosystem", "name", "version", "registry", "license", "provenance", "authority", "expires_on", "rationale"], "properties": {"id": {"type": "string", "minLength": 1}, "ecosystem": {"type": "string", "minLength": 1}, "name": {"type": "string", "minLength": 1}, "version": {"type": "string", "minLength": 1}, "registry": {"type": "string", "format": "uri"}, "license": {"type": "string", "minLength": 1}, "provenance": {"type": "string", "format": "uri"}, "authority": {"type": "string", "minLength": 1}, "expires_on": {"type": "string", "format": "date"}, "rationale": {"type": "string", "minLength": 1}}, "additionalProperties": false}
  },
  "additionalProperties": false
}

files..dset/layer_3_tool/schemas/enforcement-p:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/layer_3_tool/schemas/enforcement-profile.schema.json",
  "title": "DSET applied enforcement profile",
  "type": "object",
  "required": ["schema_version", "id", "version", "status", "profile_role", "language_family", "target_revision_policy", "evidence", "toolchain", "scope", "observed", "warning_baseline", "canonical_sequence", "gates", "known_blockers", "promotion"],
  "properties": {
    "schema_version": {"const": "1.0"},
    "id": {"type": "string", "pattern": "^[a-z][a-z0-9-]*$"},
    "version": {"type": "string", "minLength": 1},
    "status": {"enum": ["candidate", "active", "custom"]},
    "profile_role": {"enum": ["reference", "applied"]},
    "derived_from": {"type": "string", "minLength": 1},
    "language_family": {"type": "string", "minLength": 1},
    "target_revision_policy": {"enum": ["exact", "descendant"]},
    "evidence": {
      "type": "object",
      "required": ["repository", "revision", "observed_on", "license"],
      "properties": {
        "repository": {"type": "string", "format": "uri", "pattern": "^https://"},
        "revision": {"$ref": "#/$defs/sha"},
        "upstream_revision": {"$ref": "#/$defs/sha"},
        "observed_on": {"type": "string", "format": "date"},
        "license": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "toolchain": {
      "type": "object",
      "required": ["runtime", "runtime_range", "package_manager", "lockfile", "scripts"],
      "properties": {
        "runtime": {"type": "string", "minLength": 1},
        "runtime_range": {"type": "string", "minLength": 1},
        "package_manager": {"type": "string", "minLength": 1},
        "lockfile": {"$ref": "#/$defs/path"},
        "scripts": {"type": "object", "minProperties": 1, "additionalProperties": {"type": "string", "minLength": 1}}
      },
      "additionalProperties": false
    },
    "scope": {
      "type": "object",
      "required": ["source_roots", "test_roots", "required_files", "generated_outputs", "exclusions"],
      "properties": {
        "source_roots": {"$ref": "#/$defs/paths"},
        "test_roots": {"$ref": "#/$defs/paths"},
        "required_files": {"$ref": "#/$defs/paths"},
        "generated_outputs": {"$ref": "#/$defs/paths"},
        "exclusions": {"$ref": "#/$defs/paths"}
      },
      "additionalProperties": false
    },
    "observed": {"type": "object"},
    "warning_baseline": {
      "type": "object",
      "required": ["revision", "policy", "error_count", "warning_count", "rules"],
      "properties": {
        "revision": {"$ref": "#/$defs/sha"},
        "policy": {"const": "shrink-only"},
        "error_count": {"const": 0},
        "warning_count": {"type": "integer", "minimum": 0},
        "rules": {"type": "object", "additionalProperties": {"type": "integer", "minimum": 0}}
      },
      "additionalProperties": false
    },
    "canonical_sequence": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"type": "string", "minLength": 1}},
    "gates": {
      "type": "array",
      "minItems": 6,
      "maxItems": 6,
      "items": {
        "type": "object",
        "required": ["id", "status", "owner", "commands", "mechanism", "thresholds"],
        "properties": {
          "id": {"enum": ["conformance", "purity", "spec_sync", "typing_contracts", "lint_static_analysis", "secret_hygiene"]},
          "status": {"enum": ["enforced", "ratcheted", "blocked", "not-applicable"]},
          "owner": {"type": "string", "minLength": 1},
          "commands": {"type": "array", "uniqueItems": true, "items": {"type": "string", "minLength": 1}},
          "mechanism": {"type": "string", "minLength": 1},
          "thresholds": {"type": "object"},
          "reason": {"type": "string", "minLength": 1}
        },
        "additionalProperties": false
      }
    },
    "known_blockers": {"type": "array", "uniqueItems": true, "items": {"type": "string", "minLength": 1}},
    "promotion": {
      "type": "object",
      "required": ["target_id", "requires"],
      "properties": {
        "target_id": {"type": "string", "pattern": "^[a-z][a-z0-9-]*$"},
        "requires": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"type": "string", "minLength": 1}}
      },
      "additionalProperties": false
    }
  },
  "$defs": {
    "sha": {"type": "string", "pattern": "^[0-9a-f]{40}$"},
    "path": {"type": "string", "minLength": 1, "pattern": "^(?!/)(?![A-Za-z]:)(?!.*\\\\)(?!.*(?:^|/)\\.\\.(?:/|$)).+$"},
    "paths": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/path"}}
  },
  "additionalProperties": false
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/layer_3_tool/schemas/traceability.schema.json",
  "title": "DSET traceability index",
  "type": "object",
  "required": ["schema_version", "repository", "changes", "semantic_classifications", "semantic_atoms", "relations"],
  "properties": {
    "schema_version": {"enum": [1.1, "1.2", "1.3"]},
    "repository": {"type": "string"},
    "changes": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["id", "status", "path", "packages", "requirements", "tests", "evals", "intake", "decisions", "contracts", "stories", "outcomes", "pull_request", "evidence"],
        "properties": {
          "id": {"type": "string"},
          "slug": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"},
          "status": {"type": "string"},
          "path": {"type": "string"},
          "primary_layer": {"enum": ["meta", "gov", "tool", "skill", "ops"]},
          "affected_layers": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"enum": ["meta", "gov", "tool", "skill", "ops"]}},
          "workspace": {"$ref": "#/$defs/workspace"},
          "dependencies": {"type": "array", "items": {"$ref": "#/$defs/dependency"}},
          "target": {"$ref": "#/$defs/target"},
          "packages": {"type": "array", "items": {"type": "string"}},
          "requirements": {"type": "array", "items": {"type": "string"}},
          "tests": {"type": "array", "items": {"type": "string"}},
          "evals": {"type": "array", "items": {"type": "string"}},
          "intake": {"type": "array", "items": {"type": "string"}},
          "decisions": {"type": "array", "items": {"type": "string"}},
          "contracts": {"type": "array", "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-CONTRACT(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
          "stories": {"type": "array", "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-STORY(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
          "outcomes": {"type": "array", "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-OUTCOME(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"}},
          "pull_request": {"type": "string", "format": "uri"},
          "evidence": {"type": "array", "items": {"type": "string"}}
        },
        "additionalProperties": false
      }
    },
    "relations": {
      "type": "array",
      "items": {"$ref": "#/$defs/relation"}
    },
    "semantic_atoms": {
      "type": "array",
      "items": {"$ref": "#/$defs/semantic_atom"}
    },
    "semantic_classifications": {
      "type": "array",
      "items": {"$ref": "#/$defs/semantic_classification"}
    }
  },
  "allOf": [
    {
      "if": {"properties": {"schema_version": {"enum": ["1.2", "1.3"]}}, "required": ["schema_version"]},
      "then": {
        "properties": {
          "changes": {
            "items": {
              "required": ["slug", "primary_layer", "affected_layers", "workspace", "dependencies", "target"],
              "properties": {"id": {"$ref": "#/$defs/change_id"}}
            }
          }
        }
      },
      "else": {
        "properties": {
          "changes": {
            "items": {"not": {"anyOf": [{"required": ["slug"]}, {"required": ["primary_layer"]}, {"required": ["affected_layers"]}, {"required": ["workspace"]}, {"required": ["dependencies"]}, {"required": ["target"]}]}}
          }
        }
      }
    }
  ],
  "$defs": {
    "relation_id": {"type": "string", "pattern": "^[A-Z0-9]+(?:-[A-Z0-9]+)+$"},
    "semantic_atom": {
      "type": "object",
      "required": ["id", "carrier_id", "path", "sha256", "type", "subtype", "emission_status", "current_status", "priority", "priority_source", "relations", "lifecycle_events", "absorbed_by", "archived"],
      "properties": {
        "id": {"$ref": "#/$defs/relation_id"},
        "carrier_id": {"$ref": "#/$defs/relation_id"},
        "path": {"type": "string", "minLength": 1},
        "sha256": {"type": "string", "pattern": "^[0-9a-f]{64}$"},
        "type": {"enum": ["decision", "question", "problem", "qa"]},
        "subtype": {"enum": ["none", "requirement", "constraint", "contract", "user_story", "outcome", "scenario", "invariant", "conflict", "risk", "opportunity", "defect", "gap", "debt", "test", "evaluation"]},
        "emission_status": {"enum": ["proposed", "accepted"]},
        "current_status": {"enum": ["proposed", "accepted", "answered", "absorbed", "confirmed", "reopened", "rejected", "resolved", "retired", "withdrawn"]},
        "priority": {"type": "string", "minLength": 1},
        "priority_source": {"type": "string", "minLength": 1},
        "relations": {"type": "array", "items": {"$ref": "#/$defs/atom_relation"}},
        "lifecycle_events": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-LIFECYCLE-EVENT-[0-9]{3,}$"}},
        "absorbed_by": {"type": "array", "uniqueItems": true, "items": {"$ref": "#/$defs/relation_id"}},
        "archived": {"type": "boolean"}
      },
      "additionalProperties": false
    },
    "semantic_classification": {
      "type": "object",
      "required": ["id", "type", "subtype", "compatibility", "origins", "carriers", "carrier_statuses", "lifecycle_events"],
      "properties": {
        "id": {"$ref": "#/$defs/relation_id"},
        "type": {"enum": ["decision", "question", "problem", "qa"]},
        "subtype": {"enum": ["none", "requirement", "constraint", "contract", "user_story", "outcome", "scenario", "invariant", "conflict", "risk", "opportunity", "defect", "gap", "debt", "test", "evaluation"]},
        "compatibility": {"type": "boolean"},
        "origins": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"type": "string", "minLength": 1}},
        "carriers": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"type": "string", "minLength": 1}},
        "carrier_statuses": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"type": "string", "minLength": 1}},
        "lifecycle_events": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-LIFECYCLE-EVENT-[0-9]{3,}$"}}
      },
      "additionalProperties": false
    },
    "relation_type": {"enum": ["child_of", "analysis_of", "projection_of", "implementation_of", "check_of", "evidence_for", "resolution_of", "override_of", "replacement_of", "relates_to"]},
    "projection_range": {
      "type": "object",
      "required": ["semantic_type", "scope", "through"],
      "properties": {
        "semantic_type": {"enum": ["decision", "question", "problem", "qa"]},
        "subtype": {"enum": ["none", "requirement", "constraint", "contract", "user_story", "outcome", "scenario", "invariant", "conflict", "risk", "opportunity", "defect", "gap", "debt", "test", "evaluation"]},
        "layer": {"enum": ["meta", "gov", "tool", "skill", "ops"]},
        "scope": {
          "type": "object",
          "required": ["kind", "id"],
          "properties": {
            "kind": {"enum": ["project", "layer", "feature_group", "feature"]},
            "id": {"type": "string", "minLength": 1}
          },
          "additionalProperties": false
        },
        "through": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-ATOMIC-RECORD-[0-9]{3,}$"}
      },
      "additionalProperties": false
    },
    "atom_relation": {
      "type": "object",
      "required": ["type", "origin"],
      "properties": {
        "type": {"$ref": "#/$defs/relation_type"},
        "target": {"$ref": "#/$defs/relation_id"},
        "range": {"$ref": "#/$defs/projection_range"},
        "origin": {"enum": ["authored", "legacy_child_of"]}
      },
      "oneOf": [
        {"required": ["target"], "not": {"required": ["range"]}},
        {"required": ["range"], "not": {"required": ["target"]}}
      ],
      "additionalProperties": false
    },
    "relation": {
      "type": "object",
      "required": ["source", "source_kind", "type", "origin", "llm_session_ids"],
      "properties": {
        "source": {
          "oneOf": [
            {"$ref": "#/$defs/relation_id"},
            {"type": "string", "pattern": "^[0-9a-f]{40}$"}
          ]
        },
        "source_kind": {"enum": ["artifact", "commit"]},
        "source_artifact_id": {"$ref": "#/$defs/relation_id"},
        "source_path": {"type": "string", "minLength": 1},
        "type": {"$ref": "#/$defs/relation_type"},
        "target": {"$ref": "#/$defs/relation_id"},
        "range": {"$ref": "#/$defs/projection_range"},
        "origin": {"enum": ["authored", "legacy_child_of", "commit_trailer"]},
        "llm_session_ids": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$"}}
      },
      "oneOf": [
        {"required": ["target"], "not": {"required": ["range"]}},
        {"required": ["range"], "not": {"required": ["target"]}}
      ],
      "allOf": [
        {
          "if": {"properties": {"source_kind": {"const": "artifact"}}},
          "then": {"required": ["source_artifact_id", "source_path"]}
        },
        {
          "if": {"properties": {"source_kind": {"const": "commit"}}},
          "then": {
            "properties": {
              "type": {"const": "implementation_of"},
              "origin": {"const": "commit_trailer"}
            },
            "required": ["target"]
          }
        }
      ],
      "additionalProperties": false
    },
    "change_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-CHANGE-(?:META|GOV|TOOL|SKILL|OPS)-[0-9]{3,}$"},
    "trace_id": {"type": "string", "pattern": "^[A-Z][A-Z0-9]*-(?:DECISION|REQUIREMENT|CONSTRAINT|CONTRACT|STORY|OUTCOME|SCENARIO|INVARIANT|QUESTION|CONFLICT|RISK|OPPORTUNITY|PROBLEM|DEFECT|GAP|DEBT|TEST|EVAL|EVALUATION|TASK|CHANGE)(?:-(?:META|GOV|TOOL|SKILL|OPS))?-[0-9]{3,}$"},
    "sha_or_pending": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"const": "pending"}]},
    "pull_request": {
      "type": "object",
      "required": ["repository", "number", "url"],
      "properties": {
        "repository": {"type": "string", "pattern": "^[^/]+/[^/]+$"},
        "number": {"oneOf": [{"type": "integer", "minimum": 1}, {"const": "pending"}]},
        "url": {"type": "string", "minLength": 1}
      },
      "additionalProperties": false
    },
    "workspace": {
      "type": "object",
      "required": ["isolation", "branch", "base_ref", "base_commit", "head_commit"],
      "properties": {
        "isolation": {"enum": ["integration-branch", "branch-worktree"]},
        "branch": {"type": "string", "minLength": 1},
        "base_ref": {"type": "string", "minLength": 1},
        "base_commit": {"$ref": "#/$defs/sha_or_pending"},
        "head_commit": {"$ref": "#/$defs/sha_or_pending"}
      },
      "additionalProperties": false
    },
    "target": {
      "type": "object",
      "required": ["repository", "work_areas"],
      "properties": {
        "repository": {"type": "boolean"},
        "work_areas": {"type": "array", "uniqueItems": true, "items": {"type": "string", "pattern": "^[a-z0-9]+(?:-[a-z0-9]+)*$"}}
      },
      "oneOf": [
        {
          "properties": {
            "repository": {"const": true},
            "work_areas": {"maxItems": 0}
          }
        },
        {
          "properties": {
            "repository": {"const": false},
            "work_areas": {"minItems": 1}
          }
        }
      ],
      "additionalProperties": false
    },
    "dependency": {
      "type": "object",
      "required": ["change_id", "pull_request", "required_commit", "consumes", "claim", "use", "evidence", "checked_at", "reopen_when", "status"],
      "properties": {
        "change_id": {"$ref": "#/$defs/change_id"},
        "pull_request": {"$ref": "#/$defs/pull_request"},
        "required_commit": {"$ref": "#/$defs/sha_or_pending"},
        "consumes": {"type": "array", "minItems": 1, "uniqueItems": true, "items": {"$ref": "#/$defs/trace_id"}},
        "claim": {"type": "string", "minLength": 1},
        "use": {"type": "string", "minLength": 1},
        "evidence": {"type": "string", "minLength": 1},
        "checked_at": {"type": "string", "format": "date"},
        "reopen_when": {"type": "string", "minLength": 1},
        "status": {"enum": ["planned", "available", "integrated", "blocked", "stale"]}
      },
      "allOf": [
        {
          "if": {"properties": {"status": {"enum": ["available", "integrated"]}}, "required": ["status"]},
          "then": {
            "properties": {
              "pull_request": {
                "properties": {
                  "number": {"type": "integer", "minimum": 1},
                  "url": {"type": "string", "format": "uri", "pattern": "^https://"}
                }
              },
              "required_commit": {"type": "string", "pattern": "^[0-9a-f]{40}$"}
            }
          }
        }
      ],
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}

files..dset/layer_4_skill/schemas/budget.schem:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/layer_4_skill/schemas/budget.schema.json",
  "title": "DSET delegation budget policy",
  "type": "object",
  "required": ["schema_version", "default_profile", "model_policy", "profiles", "quality_floor", "no_delegation_reason_required"],
  "properties": {
    "schema_version": {"const": 1.0},
    "default_profile": {"enum": ["low", "medium", "high"]},
    "model_policy": {
      "type": "object",
      "required": ["default", "attest", "unknown_for_required_gate"],
      "properties": {
        "default": {"const": "inherit-main-model-and-effort"},
        "attest": {"const": "required-when-runtime-supports"},
        "unknown_for_required_gate": {"const": "stop-for-decision"}
      },
      "additionalProperties": false
    },
    "profiles": {
      "type": "object",
      "required": ["low", "medium", "high"],
      "properties": {
        "low": {"$ref": "#/$defs/low_profile"},
        "medium": {"$ref": "#/$defs/medium_profile"},
        "high": {"$ref": "#/$defs/high_profile"}
      },
      "additionalProperties": false
    },
    "quality_floor": {
      "type": "object",
      "required": ["preserve_requested_scope", "preserve_required_tests", "preserve_required_evals", "preserve_safety_gates"],
      "properties": {
        "preserve_requested_scope": {"const": true},
        "preserve_required_tests": {"const": true},
        "preserve_required_evals": {"const": true},
        "preserve_safety_gates": {"const": true}
      },
      "additionalProperties": false
    },
    "no_delegation_reason_required": {"const": true}
  },
  "$defs": {
    "low_profile": {
      "type": "object",
