        "max_depth": {"const": 2},
        "max_rounds": {"const": 3}
      },
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}

files..dset/layer_4_skill/schemas/session-chec:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/layer_4_skill/schemas/session-checkpoint.schema.json",
  "title": "DSET local session checkpoint",
  "type": "object",
  "required": ["schema_version", "session_id", "llm_session_ids", "sequence", "updated_at", "status", "persistence", "public_entrypoint", "root_run_id", "latest_run_id", "active_run_ids", "scope", "objective", "ruleset_identity", "completed", "pending", "authorization", "touched_paths", "authority_snapshot", "closure", "next"],
  "properties": {
    "schema_version": {"const": "1.3"},
    "session_id": {"$ref": "#/$defs/id"},
    "llm_session_ids": {"type": "array", "maxItems": 8, "uniqueItems": true, "items": {"$ref": "#/$defs/llm_session_id"}},
    "rationale": {"$ref": "#/$defs/rationale"},
    "sequence": {"type": "integer", "minimum": 0},
    "updated_at": {"type": "string", "format": "date-time", "maxLength": 40},
    "status": {"enum": ["active", "paused", "completed", "stopped"]},
    "persistence": {"enum": ["persisted", "unavailable"]},
    "public_entrypoint": {"enum": ["dset", "dset-init", "dset-repair-governance", "dset-decompose", "dset-diagnose", "dset-clarify", "dset-landscape", "dset-prototype", "dset-decisions", "dset-plan-proof", "dset-plan-implementation", "dset-implement", "dset-verify", "dset-overview", "dset-triage", "dset-release", "dset-complete"]},
    "root_run_id": {"$ref": "#/$defs/id"},
    "latest_run_id": {"$ref": "#/$defs/id"},
    "active_run_ids": {"type": "array", "maxItems": 32, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}},
    "scope": {"$ref": "#/$defs/scope"},
    "objective": {"type": "string", "minLength": 1, "maxLength": 1024},
    "ruleset_identity": {"oneOf": [{"$ref": "#/$defs/id"}, {"type": "null"}]},
    "completed": {
      "type": "array",
      "maxItems": 64,
      "items": {"$ref": "#/$defs/work_pointer"}
    },
    "pending": {
      "type": "array",
      "maxItems": 32,
      "items": {"$ref": "#/$defs/work_pointer"}
    },
    "authorization": {
      "type": "object",
      "required": ["class", "state"],
      "properties": {
        "class": {"enum": ["read-only", "repository-write", "external-write", "publication", "unknown"]},
        "state": {"enum": ["granted", "not-granted", "consumed", "unknown"]}
      },
      "additionalProperties": false
    },
    "touched_paths": {
      "type": "array",
      "maxItems": 64,
      "uniqueItems": true,
      "items": {"$ref": "#/$defs/relative_path"}
    },
    "authority_snapshot": {
      "type": "object",
      "required": ["git_commit", "working_tree_digest", "change_manifest", "proof_ids", "hosted_refs"],
      "properties": {
        "git_commit": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{40}$"}, {"type": "null"}]},
        "working_tree_digest": {"oneOf": [{"type": "string", "pattern": "^[0-9a-f]{64}$"}, {"type": "null"}]},
        "change_manifest": {"oneOf": [{"$ref": "#/$defs/relative_path"}, {"type": "null"}]},
        "proof_ids": {"type": "array", "maxItems": 32, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}},
        "hosted_refs": {"type": "array", "maxItems": 16, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}}
      },
      "additionalProperties": false
    },
    "closure": {
      "type": "object",
      "required": ["schema_version", "requested_mode", "status", "criteria", "next_workflow", "reason_code", "history", "visited_states"],
      "properties": {
        "schema_version": {"const": "1.0"},
        "requested_mode": {"oneOf": [{"$ref": "#/$defs/id"}, {"type": "null"}]},
        "status": {"enum": ["direct", "active", "blocked", "authorization-required", "ready", "completed", "stopped"]},
        "criteria": {"type": "object", "additionalProperties": {"type": ["boolean", "null"]}, "maxProperties": 16},
        "next_workflow": {"oneOf": [{"$ref": "#/$defs/id"}, {"type": "null"}]},
        "reason_code": {"$ref": "#/$defs/id"},
        "history": {
          "type": "array",
          "maxItems": 16,
          "items": {
            "type": "object",
            "required": ["workflow_id", "status", "progress"],
            "properties": {
              "workflow_id": {"$ref": "#/$defs/id"},
              "status": {"enum": ["succeeded", "failed", "stopped", "ambiguous"]},
              "progress": {"type": "array", "maxItems": 16, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}}
            },
            "additionalProperties": false
          }
        },
        "visited_states": {"type": "array", "maxItems": 32, "uniqueItems": true, "items": {"type": "string", "pattern": "^state:[0-9a-f]{64}$"}}
      },
      "additionalProperties": false
    },
    "next": {
      "type": "object",
      "required": ["mode", "reason_code", "requires_authorization"],
      "properties": {
        "mode": {"enum": ["initialize", "repair-governance", "decompose", "diagnose", "clarify", "landscape", "prototype", "decisions", "plan-proof", "plan-implementation", "implement", "verify", "overview", "triage-work", "release", "complete"]},
        "reason_code": {"$ref": "#/$defs/id"},
        "requires_authorization": {"enum": ["none", "repository-write", "external-write", "publication"]}
      },
      "additionalProperties": false
    }
  },
  "$defs": {
    "id": {"type": "string", "pattern": "^[A-Za-z0-9][A-Za-z0-9._:-]{0,127}$"},
    "llm_session_id": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$", "maxLength": 160},
    "rationale": {"type": "string", "minLength": 1, "maxLength": 1024},
    "nullable_scope": {"oneOf": [{"type": "string", "pattern": "^[A-Za-z0-9][A-Za-z0-9._:/-]{0,127}$"}, {"type": "null"}]},
    "relative_path": {"type": "string", "maxLength": 512, "pattern": "^(?!/)(?!.*\\.\\./)[A-Za-z0-9._-]+(?:/[A-Za-z0-9._-]+)*$"},
    "scope": {
      "type": "object",
      "required": ["repository", "workspace", "project", "package", "change", "target"],
      "properties": {
        "repository": {"$ref": "#/$defs/nullable_scope"},
        "workspace": {"$ref": "#/$defs/nullable_scope"},
        "project": {"$ref": "#/$defs/nullable_scope"},
        "package": {"$ref": "#/$defs/nullable_scope"},
        "change": {"$ref": "#/$defs/nullable_scope"},
        "target": {"$ref": "#/$defs/target"}
      },
      "additionalProperties": false
    },
    "target": {
      "type": "object",
      "required": ["repository", "work_areas"],
      "properties": {
        "repository": {"type": "boolean"},
        "work_areas": {"type": "array", "maxItems": 32, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}}
      },
      "oneOf": [
        {"properties": {"repository": {"const": true}, "work_areas": {"maxItems": 0}}},
        {"properties": {"repository": {"const": false}, "work_areas": {"minItems": 1}}}
      ],
      "additionalProperties": false
    },
    "work_pointer": {
      "type": "object",
      "required": ["kind", "id", "path"],
      "properties": {
        "kind": {"enum": ["artifact", "workflow", "proof", "diagnostic", "handoff"]},
        "id": {"oneOf": [{"$ref": "#/$defs/id"}, {"type": "null"}]},
        "path": {"oneOf": [{"$ref": "#/$defs/relative_path"}, {"type": "null"}]}
      },
      "anyOf": [
        {"properties": {"id": {"$ref": "#/$defs/id"}}},
        {"properties": {"path": {"$ref": "#/$defs/relative_path"}}}
      ],
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}

