        "requested_effort": {"$ref": "#/$defs/nullable_id"},
        "effective_model": {"$ref": "#/$defs/nullable_id"},
        "effective_effort": {"$ref": "#/$defs/nullable_id"},
        "attestation": {"enum": ["confirmed", "runtime-default-unverified", "unsupported"]},
        "planned_subagents": {"type": "integer", "minimum": 0, "maximum": 6},
        "actual_subagents": {"type": "integer", "minimum": 0, "maximum": 6},
        "planned_rounds": {"type": "integer", "minimum": 0, "maximum": 3},
        "actual_rounds": {"type": "integer", "minimum": 0, "maximum": 3},
        "deviations": {"type": "array", "maxItems": 8, "items": {"$ref": "#/$defs/stable_code"}}
      },
      "allOf": [
        {
          "if": {"properties": {"profile": {"const": "low"}}},
          "then": {"properties": {"planned_subagents": {"maximum": 1}, "actual_subagents": {"maximum": 1}, "planned_rounds": {"maximum": 1}, "actual_rounds": {"maximum": 1}}}
        },
        {
          "if": {"properties": {"profile": {"const": "medium"}}},
          "then": {"properties": {"planned_subagents": {"maximum": 3}, "actual_subagents": {"maximum": 3}, "planned_rounds": {"maximum": 2}, "actual_rounds": {"maximum": 2}}}
        }
      ],
      "additionalProperties": false
    },
    "usage": {
      "oneOf": [
        {"type": "null"},
        {
          "type": "object",
          "properties": {
            "input_tokens": {"type": "integer", "minimum": 0},
            "output_tokens": {"type": "integer", "minimum": 0},
            "currency": {"type": "string", "pattern": "^[A-Z]{3}$"},
            "cost": {"type": "number", "minimum": 0}
          },
          "additionalProperties": false
        }
      ]
    }
  },
  "allOf": [
    {
      "if": {"properties": {"status": {"const": "running"}}},
      "then": {"properties": {"finished_at": {"type": "null"}, "persistence": {"const": "persisted"}}},
      "else": {"properties": {"finished_at": {"type": "string", "format": "date-time", "maxLength": 40}}}
    },
    {
      "if": {"properties": {"persistence": {"const": "unavailable"}}},
      "then": {"properties": {"status": {"enum": ["succeeded", "failed", "stopped", "interrupted"]}}}
    }
  ],
  "$defs": {
    "id": {"type": "string", "pattern": "^[A-Za-z0-9][A-Za-z0-9._:-]{0,127}$"},
    "llm_session_id": {"type": "string", "pattern": "^[a-z][a-z0-9_-]*:[A-Za-z0-9._:-]+$", "maxLength": 160},
    "rationale": {"type": "string", "minLength": 1, "maxLength": 1024},
    "nullable_id": {"oneOf": [{"$ref": "#/$defs/id"}, {"type": "null"}]},
    "nullable_scope": {"oneOf": [{"type": "string", "pattern": "^[A-Za-z0-9][A-Za-z0-9._:/-]{0,127}$"}, {"type": "null"}]},
    "target": {
      "type": "object",
      "required": ["repository", "work_areas"],
      "properties": {
        "repository": {"type": "boolean"},
        "work_areas": {"type": "array", "maxItems": 32, "uniqueItems": true, "items": {"$ref": "#/$defs/id"}}
      },
      "oneOf": [
        {"properties": {"repository": {"const": true}, "work_areas": {"maxItems": 0}}},
        {"properties": {"repository": {"const": false}, "work_areas": {"minItems": 1}}}
      ],
      "additionalProperties": false
    },
    "relative_path": {"type": "string", "maxLength": 512, "pattern": "^(?!/)(?!.*\\.\\./)[A-Za-z0-9._-]+(?:/[A-Za-z0-9._-]+)*$"},
    "stable_code": {"type": "string", "maxLength": 64, "pattern": "^[A-Z][A-Z0-9]*(?:-[A-Z0-9]+){1,5}$"},
    "parameter_name": {"enum": ["operation", "change_profile", "budget_profile", "applicability", "authorization", "scope_kind", "source_kind", "target_kind", "result_class", "risk_class"]},
    "parameter": {
      "oneOf": [
        {
          "type": "object",
          "required": ["name", "representation", "value"],
          "properties": {
            "name": {"$ref": "#/$defs/parameter_name"},
            "representation": {"const": "category"},
            "value": {"enum": ["none", "small", "standard", "large", "defect", "adoption", "low", "medium", "high", "applicable", "not-applicable", "read-only", "write-authorized", "automatic", "manual", "local", "hosted", "success", "failure", "stopped", "unknown"]}
          },
          "additionalProperties": false
        },
        {
          "type": "object",
          "required": ["name", "representation", "value"],
          "properties": {
            "name": {"$ref": "#/$defs/parameter_name"},
            "representation": {"const": "sha256"},
            "value": {"type": "string", "pattern": "^[0-9a-f]{64}$"}
          },
          "additionalProperties": false
        },
        {
          "type": "object",
          "required": ["name", "representation", "value"],
          "properties": {
            "name": {"$ref": "#/$defs/parameter_name"},
            "representation": {"const": "redacted"},
            "value": {"const": "[redacted]"}
          },
          "additionalProperties": false
        }
      ]
    }
  },
  "additionalProperties": false
}

files..dset/layer_5_ops/schemas/pull-request-h:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://raw.githubusercontent.com/anatoly-m-maslennikov/dset-specs-loops-framework/main/.dset/layer_5_ops/schemas/pull-request-history.schema.json",
  "title": "DSET GitHub PR history snapshot",
  "type": "object",
  "required": ["schema_version", "repository", "authoritative_source", "observed_on", "pull_requests"],
  "properties": {
    "schema_version": {"const": 1.0},
    "repository": {"type": "string"},
    "authoritative_source": {"const": "github"},
    "observed_on": {"type": "string", "format": "date"},
    "pull_requests": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["number", "title", "state", "base", "head", "url"],
        "properties": {
          "number": {"type": "integer", "minimum": 1},
          "title": {"type": "string"},
          "state": {"enum": ["open", "merged", "closed"]},
          "draft": {"type": "boolean"},
          "base": {"type": "string"},
          "head": {"type": "string"},
          "merge_commit": {"type": ["string", "null"], "pattern": "^[0-9a-f]{40}$"},
          "url": {"type": "string", "format": "uri"}
        },
        "additionalProperties": false
      }
    }
  },
  "additionalProperties": false
}
